        if (header == null) {
            throw new SOAPSecurityException("Missing SOAP header");
        }

        SOAPElement security = findElement(header, SecurityConstants.WSSE_NS, "Security");
        if (security == null) {
            throw new SOAPSecurityException("Missing wsse:Security header");
        }

        SOAPElement timestamp = findElement(security, SecurityConstants.WSU_NS, "Timestamp");
        if (timestamp == null) {
            throw new SOAPSecurityException("Missing wsu:Timestamp");
        }

        String id = getAttribute(timestamp, SecurityConstants.WSU_NS, "Id");
        String created = getChildText(timestamp, SecurityConstants.WSU_NS, "Created");
        String expires = getChildText(timestamp, SecurityConstants.WSU_NS, "Expires");

        if (created == null || expires == null) {
            throw new SOAPSecurityException("Timestamp must contain Created and Expires");
        }

        Instant createdInstant = Instant.parse(created);
        Instant expiresInstant = Instant.parse(expires);
        Instant now = Instant.now();

        if (expiresInstant.isBefore(createdInstant)) {
            throw new SOAPSecurityException("Timestamp Expires is before Created");
        }

        if (Duration.between(createdInstant, expiresInstant).compareTo(MAX_TIMESTAMP_TTL) > 0) {
            throw new SOAPSecurityException("Timestamp TTL exceeds maximum allowed window");
        }

        if (createdInstant.isAfter(now.plus(ALLOWED_CLOCK_SKEW))) {
            throw new SOAPSecurityException("Timestamp Created is in the future");
        }

        if (expiresInstant.isBefore(now.minus(ALLOWED_CLOCK_SKEW))) {
            throw new SOAPSecurityException("Timestamp has expired");
        }

        String replayKey = (id != null ? id : "") + "|" + created + "|" + expires;
        if (!SEEN_TIMESTAMPS.add(replayKey)) {
            throw new SOAPSecurityException("Replay detected for timestamp");
        }

